<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="科室名称"
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入科室名称"
                  v-model:value="queryParams.name"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
        <a-button
          @click="hanleTc"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >科室检测项
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="科室名称" name="name">
            <a-input placeholder="请输入科室名称" v-model:value="form.name" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="科室编码" name="code">
            <a-input placeholder="请输入科室编码" v-model:value="form.code" />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="科室长姓名" :rules="[{ required: true, message: '该项必填！' }]">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.teamLead"
              placeholder="请选科室长姓名"
            >
              <a-select-option
                v-for="item in selUserList"
                :key="item.name"
                :lable="item.name"
                :value="item.name"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="科室队长电话" name="leadTel">
            <a-input
              placeholder="请输入科室长电话"
              v-model:value="form.leadTel"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="副科室长姓名">
            <a-select
              :allowClear="true"
              showSearch
              optionFilterProp="lable"
              v-model:value="form.teamLead1"
              placeholder="请选副科室长姓名"
            >
              <a-select-option
                v-for="item in selUserList"
                :key="item.name"
                :lable="item.name"
                :value="item.name"
              >
                {{ item.name }}
              </a-select-option>
            </a-select>
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="备注">
            <a-textarea
              rows="4"
              placeholder="备注信息"
              v-model:value="form.remark"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
  <a-modal
    :visible="openTc"
    :title="title"
    width="650px"
    :footer="null"
    :destroyOnClose="true"
    @cancel="handleCancelTc"
  >
    <teamCheckItem
      :Code="selectedRowKeys[0]"
      :ResList="RecordListRes"
    ></teamCheckItem>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "科室名称",
    dataIndex: "name",
  },
  {
    title: "科室人数",
    dataIndex: "technicistCount",
  },
  {
    title: "科室长名称",
    dataIndex: "teamLead",
  },
  {
    title: "科室长电话",
    dataIndex: "leadTel",
  },
  {
    title: "副科室长名称",
    dataIndex: "teamLead1",
  },
  {
    title: "组建时间",
    dataIndex: "createTime",
  },
];
const rules = {
  leadTel: [
    {
      pattern:
        /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
      message: "手机号不合法",
      trigger: "blur",
    },
    { required: true, message: "该为必填项", trigger: "blur" },
  ],
  code: [{ required: true, message: "该为必填项", trigger: "blur" }],
  name: [{ required: true, message: "该为必填项", trigger: "blur" }],
};
import {
  TestCheckItemTeamRelList,
  teamList,
  addTeam,
  getTeam,
  delTeam,
  editTeam,
  UserList,
} from "@/server/http/api/team";
import { message } from "ant-design-vue";
import teamCheckItem from "../../views/team/teamCheckItem.vue";
export default {
  name: "QueryList",
  components: { teamCheckItem },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      openTc: false,
      advanced: false,
      columns: columns,
      rules: rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        name: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      //用户列表
      selUserList: [],
      //用来保存检测项信息
      RecordListRes: [],
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
    this.getUserList();
  },
  methods: {
    //关闭科室检测项
    handleCancelTc() {
      this.openTc = false;
    },
    //打开科室检测项
    hanleTc() {
      TestCheckItemTeamRelList({
        current: 1,
        size: 5,
        teamId: this.selectedRowKeys[0],
      }).then((res) => {
        this.RecordListRes = res;
        this.openTc = true;
        this.title = "科室检测项管理";
      });
    },
    //获取用户
    getUserList() {
      UserList().then((res) => {
        var data = res.data.data;
        this.selUserList = data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      teamList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },
    handleOk(e) {
      var myreg =
        /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/;
      if (
        !myreg.test(this.form.leadTel) ||
        !this.form.name ||
        !this.form.code||
        !this.form.teamLead
      ) {
        message.warning("缺少必填参数!");
         return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      //this.reset();
      this.open = true;
      this.title = "添加科室";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getTeam(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改科室信息";
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        editTeam(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addTeam(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delTeam(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>