<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div class="fold">
          <a-row :gutter="[16, 16]">
            <a-col :span="12">
              <a-form-item
                label="产品"
                :rules="[{ required: true, message: '该项必填！' }]"
              >
                <a-select
                  showSearch
                  optionFilterProp="lable"
                  v-model:value="province"
                  placeholder="请选择产品"
                  :allowClear="true"
                  style="width: 180px"
                >
                  <a-select-option
                    v-for="item in productList"
                    :key="item.productId"
                    :lable="item.productName"
                    :value="item.productId"
                  >
                    {{ item.productName }}
                  </a-select-option>
                </a-select>
              </a-form-item>
            </a-col>
            <a-col :span="12">
              <a-form-item
                label="检测项"
                :rules="[{ required: true, message: '该项必填！' }]"
              >
                <a-tree-select
                  v-model:value="form.checkItemId"
                  showSearch
                  treeNodeFilterProp="checkItemName"
                  style="width: 180px"
                  placeholder="请选择检测项"
                  :dropdown-style="{ maxHeight: '400px', overflow: 'auto' }"
                  notFoundContent="未选择产品或产品下没有检测项"
                  allow-clear
                  :tree-data="productItemList"
                  :replaceFields="{
                    children: 'children',
                    label: 'checkItemName',
                    key: 'checkItemId',
                    value: 'checkItemId',
                  }"
                ></a-tree-select>
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 30px">
          <a-button type="primary" @click="submitForm">{{
            form.id == null ? "添加" : "保存"
          }}</a-button>
          <a-button style="margin-left: 8px" @click="reset">重置</a-button>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary" v-if="form.id != null"
          >切换添加</a-button
        >
        <a-button
          v-if="form.id == null"
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>
</template>

<script>
const columns = [
  {
    title: "科室名称",
    dataIndex: "teamName",
  },
  {
    title: "产品编号",
    dataIndex: "productId",
  },
  {
    title: "产品名称",
    dataIndex: "productName",
  },
  {
    title: "检测项编号",
    dataIndex: "checkItemId",
  },
  {
    title: "检测项名称",
    dataIndex: "checkItemName",
  },
];
import { message } from "ant-design-vue";
import { UploadOutlined } from "@ant-design/icons-vue";
import {
  TestCheckItemTeamRelList,
  addTestCheckItemTeamRel,
  getTestCheckItemTeamRel,
  delTestCheckItemTeamRel,
  editTestCheckItemTeamRel,
} from "@/server/http/api/team";
import { ProductListAll, itemList, getitem } from "@/server/http/api/Product";
import { number } from "echarts";
export default {
  name: "QueryList",
  components: { UploadOutlined },
  props: {
    Code: number,
    ResList: Object,
  },
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {
        id: null,
        productId: null,
        checkItemId: null,
      },
      file: null,
      Pagination: {},
      total: 0,
      queryParams: {
        current: 1,
        size: 5,
        teamId: this.Code,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      fileList: [],
      // 产品列表
      productList: [],
      // 产品检测项
      productItemList: [],
      //暂存产品ID
      province: null,
      //暂存修改信息
      updForm: null,
    };
  },
  authorize: {
    deleteTestCheckItemTeamRel: "delete",
  },
  mounted() {
    this.getProductList();
  },
  created() {
    this.form = {
      teamId: this.Code,
      id: null,
      productId: null,
      checkItemId: null,
    };
    var data = this.ResList.data;
    this.dataSource = data.data.records;
    this.total = data.data.total;
  },
  watch: {
    province(e) {
      this.form.productId = e;
      this.form.checkItemId = null;
      if (e == null || e == "") {
        this.productItemList = [];
        return;
      }
      itemList({
        productId: e,
        status: "0",
      }).then((res) => {
        var data = res.data;
        this.productItemList = data.data;
      });
      if (this.updForm != null) {
        this.form = this.updForm;
      }
    },
    ResList(res) {
      var data = res.data;
      this.dataSource = data.data.records;
      this.total = data.data.total;
    },
  },
  methods: {
    //获取产品列表
    getProductList() {
      ProductListAll().then((res) => {
        var data = res.data;
        this.productList = data.data;
      });
    },
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      TestCheckItemTeamRelList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    handleOk(e) {
      if (
        !this.form.checkItemId
      ) {
        message.warning("缺少必填参数!");
        return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.form = {
        teamId: this.Code,
        id: null,
        productId: null,
        checkItemId: null,
      };
      this.open = false;
    },
    deleteTestCheckItemTeamRel(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.form = {
        teamId: this.Code,
        id: null,
        productId: null,
        checkItemId: null,
      };
      this.province = null;
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getTestCheckItemTeamRel(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.updForm = response.data.data;
        this.province = response.data.data.productId;
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        editTestCheckItemTeamRel(this.form)
          .then((response) => {
            this.open = false;
            this.form = {
              teamId: this.Code,
              id: null,
              productId: null,
              checkItemId: null,
            };
            this.province = null;
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addTestCheckItemTeamRel(this.form)
          .then((response) => {
            this.form = {
              teamId: this.Code,
              id: null,
              productId: null,
              checkItemId: null,
            };
            this.province = null;
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delTestCheckItemTeamRel(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.form = {
            teamId: this.Code,
            id: null,
            productId: null,
            checkItemId: null,
          };
          this.province = null;
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
    reset() {
      if (this.form.id != null) {
        this.handleUpdate(null);
      } else {
        this.form = {
          teamId: this.Code,
          id: null,
          productId: null,
          checkItemId: null,
        };
        this.province = null;
      }
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: 350px;
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
</style>
